content.text:
targetScope = 'subscription'

param location string = 'eastus'
param environment string

// Create a resource group
resource rg 'Microsoft.Resources/resourceGroups@2022-09-01' = {
  name: 'app-${environment}-rg'
  location: location
}

// Assign a built-in policy at subscription scope
resource policyAssignment 'Microsoft.Authorization/policyAssignments@2022-06-01' = {
  name: 'allowed-locations'
  properties: {
    policyDefinitionId: '/providers/Microsoft.Authorization/policyDefinitions/e56962a6-4747-49cd-b67b-bf8b01975c4f'
    parameters: {
      listOfAllowedLocations: {
        value: [location]
      }
    }
  }
}

// Nested module deployment into the resource group just created
module appInfra 'modules/app.bicep' = {
  scope: rg
  name: 'appInfra'
  params: {
    location: location
  }
}

targetScope = 'managementGroup'

// Define a policy that applies across all child subscriptions
resource policyDef 'Microsoft.Authorization/policyDefinitions@2021-06-01' = {
  name: 'require-tags'
  properties: {
    policyType: 'Custom'
    mode: 'All'
    displayName: 'Require cost-center and environment tags'
    policyRule: {
      if: {
        field: 'tags[cost-center]'
        exists: 'false'
      }
      then: {
        effect: 'deny'
      }
    }
  }
}

targetScope = 'tenant'

// Create a top-level management group
resource corp 'Microsoft.Management/managementGroups@2021-04-01' = {
  name: 'corp'
  properties: {
    displayName: 'Corporate'
  }
}

// Assign Owner to a service principal at tenant root
resource ownerAssignment 'Microsoft.Authorization/roleAssignments@2022-04-01' = {
  name: guid('tenant-owner', principalId)
  properties: {
    roleDefinitionId: tenantResourceId(
      'Microsoft.Authorization/roleDefinitions',
      '8e3af657-a8ff-443c-a75c-2fe8c4bcb635'
    )
    principalId: principalId
    principalType: 'ServicePrincipal'
  }
}

// main.bicep — targetScope defaults to 'resourceGroup'

// Reference an existing resource group in a different subscription
resource externalRG 'Microsoft.Resources/resourceGroups@2022-09-01' existing = {
  name: 'shared-rg'
  scope: subscription('xxxxxxxx-xxxx-xxxx-xxxx-xxxxxxxxxxxx')
}

// Deploy a module into a different resource group in the same subscription
module sharedInfra 'modules/shared.bicep' = {
  scope: resourceGroup('networking-rg')
  name: 'sharedInfra'
  params: {
    vnetId: externalRG.id
  }
}

# provider.tf
provider "azurerm" {
  features {}
  subscription_id = var.subscription_id
}

# Subscription-scoped resources (e.g. resource groups, sub-wide policies)
# are created with standard azurerm resources:
resource "azurerm_resource_group" "app" {
  name     = "app-prod-rg"
  location = var.location
}

# Management group resources use the azurerm_management_group_* family:
resource "azurerm_management_group_policy_assignment" "require_tags" {
  name                 = "require-tags"
  management_group_id  = data.azurerm_management_group.corp.id
  policy_definition_id = azurerm_policy_definition.require_tags.id
}
